"use client";

import {
  memo,
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import type {
  CommentThread01Handle,
} from "@/registry/components/data/comment-thread-01";
import { defaultRelativeTime, toDate } from "@/registry/components/data/comment-thread-01";
import type {
  EngagementBar01Handle,
  EngagementDelta,
} from "@/registry/components/data/engagement-bar-01";
import {
  DEFAULT_POST_CARD_LABELS,
  type Post,
  type PostCard01Props,
  type PostCard01Labels,
  type PostHandlers,
  type PostLikeUser,
} from "./types";
import {
  defaultPostEngagementActions,
  defaultPostKebabActions,
} from "./lib/defaults";
import { FeedVariant } from "./parts/feed-variant";
import { CompactVariant } from "./parts/compact-variant";
import { ListVariant } from "./parts/list-variant";
import { DetailVariant } from "./parts/detail-variant";
import { LikersStrip } from "./parts/likers-strip";
import { ShareMenu } from "./parts/share-menu";
import { CommentThread01 } from "@/registry/components/data/comment-thread-01";

function PostCard01Inner(props: PostCard01Props) {
  const {
    variant,
    post: initialPost,
    currentUser,

    commentThread,
    commentPageSize = 10,

    onLike,
    onComment,
    onShare,
    onBookmark,

    onAddComment,
    onLikeComment,
    onDeleteComment,
    onReportComment,
    onLoadMoreComments,
    onCopyLink,
    onReport,

    engagementSubscribe,
    commentSubscribe,
    onSubscribeEngagementDelta,
    onSubscribeCommentDelta,

    getHref,
    linkComponent,
    disableHeartBurst = false,

    engagementMode = "inline",
    likers: initialLikers,
    onLoadMoreLikers,
    shareSuggestions,
    onShareSearch,
    onShareTo,
    inlineCommentsMaxHeight = "24rem",
    defaultInlinePanel = "none",
    openLikersOnLike = true,

    renderHeader,
    renderContent,
    renderMedia,
    engagementActions: engagementActionsSlot,
    renderEngagementBar,
    kebabActions,
    commentActions,
    renderCommentSection,

    headingAs,
    bodyMaxLines: bodyMaxLinesProp,

    labels: labelsProp,
    className,
    headerClassName,
    bodyClassName,
    mediaClassName,
    engagementClassName,
    commentSectionClassName,

    ref,
  } = props;

  // ─── Always-uncontrolled `post` — stateful from mount; updated via reset() handle ───
  const [statefulPost, setStatefulPost] = useState<Post>(initialPost);

  // ─── Inline panel state (only meaningful when engagementMode === "inline") ───
  // detail variant ignores inline mode (it always shows the thread).
  const inlineModeActive = engagementMode === "inline" && variant !== "detail";
  const [activePanel, setActivePanel] = useState<
    "none" | "likes" | "comments" | "share"
  >(inlineModeActive ? defaultInlinePanel : "none");
  const [statefulLikers, setStatefulLikers] = useState<PostLikeUser[]>(
    initialLikers ?? [],
  );

  const labels = useMemo<
    Required<
      Omit<PostCard01Labels, "formatRelativeTime" | "engagementLabels" | "commentLabels">
    >
  >(
    () => ({ ...DEFAULT_POST_CARD_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const format = labelsProp?.formatRelativeTime ?? defaultRelativeTime;
  const formattedTime = format(toDate(statefulPost.createdAt), new Date());

  // ─── Heart-burst + variant defaults ───
  const resolvedHeadingAs: "h2" | "h3" | "h4" =
    headingAs ?? (variant === "detail" ? "h2" : "h3");
  const resolvedBodyMaxLines =
    bodyMaxLinesProp ??
    (variant === "feed"
      ? 3
      : variant === "compact" || variant === "list"
        ? 2
        : 0);

  const heartBurstWired =
    !disableHeartBurst &&
    (statefulPost.media?.length ?? 0) > 0 &&
    !!onLike &&
    (variant === "feed" || variant === "detail");

  const cardLinkable = !!getHref && variant !== "detail";
  const linkHref = getHref ? getHref(statefulPost) : undefined;
  const LinkComponent = linkComponent ?? "a";

  // ─── Local mirror updates via realtime subscribe (R-Plan-1 + R-Plan-4) ───
  const onSubscribeEngagementDeltaRef = useRef(onSubscribeEngagementDelta);
  useEffect(() => {
    onSubscribeEngagementDeltaRef.current = onSubscribeEngagementDelta;
  });

  useEffect(() => {
    if (!engagementSubscribe) return;
    const unsub = engagementSubscribe((delta: EngagementDelta) => {
      onSubscribeEngagementDeltaRef.current?.(delta);
      setStatefulPost((prev) => {
        switch (delta.kind) {
          case "like-changed":
            return {
              ...prev,
              likes: delta.count,
              isLiked: delta.liked ?? prev.isLiked,
            };
          case "bookmark-changed":
            return { ...prev, isBookmarked: delta.bookmarked };
          case "comment-count-changed":
            return { ...prev, comments: delta.count };
          case "share-count-changed":
            return { ...prev, shares: delta.count };
          case "view-count-changed":
            return { ...prev, viewCount: delta.count };
          default:
            return prev;
        }
      });
    });
    return unsub;
  }, [engagementSubscribe]);

  // ─── Wrapped handlers (R-Plan-2) — dispatch local mirror first, then fire host's handler ───
  const handleLike = useCallback(
    (id: string, next: boolean) => {
      setStatefulPost((prev) => ({
        ...prev,
        isLiked: next,
        likes: next ? prev.likes + 1 : Math.max(0, prev.likes - 1),
      }));
      onLike?.(id, next);
      // Inline mode: open likers panel on a fresh like (kasder UX).
      if (inlineModeActive && next && openLikersOnLike) {
        setActivePanel("likes");
      }
    },
    [onLike, inlineModeActive, openLikersOnLike],
  );

  const handleBookmark = useCallback(
    (id: string, next: boolean) => {
      setStatefulPost((prev) => ({ ...prev, isBookmarked: next }));
      onBookmark?.(id, next);
    },
    [onBookmark],
  );

  // Under inline mode, comment-icon click toggles the inline comments panel
  // instead of firing the host's onComment.
  const handleComment = useCallback(
    (id: string) => {
      if (inlineModeActive) {
        setActivePanel((prev) => (prev === "comments" ? "none" : "comments"));
      } else {
        onComment?.(id);
      }
    },
    [inlineModeActive, onComment],
  );

  // Under inline mode + shareSuggestions provided, share toggles the share panel
  // instead of firing the host's onShare.
  const handleShare = useCallback(
    (id: string) => {
      if (inlineModeActive && shareSuggestions) {
        setActivePanel((prev) => (prev === "share" ? "none" : "share"));
      } else {
        onShare?.(id);
      }
    },
    [inlineModeActive, shareSuggestions, onShare],
  );

  const wrappedHandlers: PostHandlers = useMemo(
    () => ({
      onLike: handleLike,
      onComment: handleComment,
      onShare: handleShare,
      onBookmark: handleBookmark,
    }),
    [handleLike, handleComment, handleShare, handleBookmark],
  );

  // ─── Default kebab handlers ───
  const handleCopyLink = useCallback(
    (id: string) => {
      if (onCopyLink) {
        onCopyLink(id);
      } else if (getHref && typeof navigator !== "undefined" && navigator.clipboard) {
        // Default: write the href to clipboard
        const href = getHref(statefulPost);
        if (href) {
          void navigator.clipboard.writeText(
            href.startsWith("http")
              ? href
              : typeof window !== "undefined"
                ? new URL(href, window.location.origin).toString()
                : href,
          );
        }
      }
    },
    [onCopyLink, getHref, statefulPost],
  );

  const handleReport = useCallback(
    (id: string) => {
      onReport?.(id);
    },
    [onReport],
  );

  // Inline-mode: count tap on the like action toggles the likers panel
  // (heart icon stays bound to onToggle).
  const handleLikeCountClick = useCallback(() => {
    if (!inlineModeActive) return;
    setActivePanel((prev) => (prev === "likes" ? "none" : "likes"));
  }, [inlineModeActive]);

  // ─── Engagement actions array (mirrored post + wrapped handlers) ───
  const engagementActionsArr = useMemo(
    () =>
      engagementActionsSlot
        ? engagementActionsSlot(statefulPost, wrappedHandlers, variant)
        : defaultPostEngagementActions(
            statefulPost,
            wrappedHandlers,
            variant,
            inlineModeActive ? handleLikeCountClick : undefined,
          ),
    [
      engagementActionsSlot,
      statefulPost,
      wrappedHandlers,
      variant,
      inlineModeActive,
      handleLikeCountClick,
    ],
  );

  // ─── Kebab items ───
  const kebabItems = useMemo(() => {
    if (kebabActions) return kebabActions(statefulPost);
    return defaultPostKebabActions(
      statefulPost,
      {
        onBookmark: handleBookmark,
        onShare,
        onReport: onReport ? handleReport : undefined,
        onCopyLink:
          onCopyLink || getHref ? handleCopyLink : undefined,
      },
      labels,
    );
  }, [
    kebabActions,
    statefulPost,
    handleBookmark,
    onShare,
    onReport,
    handleReport,
    onCopyLink,
    getHref,
    handleCopyLink,
    labels,
  ]);

  // ─── State + refs ───
  const [kebabOpen, setKebabOpen] = useState(false);
  const [burstKey, setBurstKey] = useState(0);
  const barRef = useRef<EngagementBar01Handle | null>(null);
  const threadRef = useRef<CommentThread01Handle | null>(null);
  const statefulPostRef = useRef<Post>(statefulPost);
  useEffect(() => {
    statefulPostRef.current = statefulPost;
  });

  const onMediaDoubleTap = useCallback(() => {
    if (!heartBurstWired) return;
    barRef.current?.triggerLike();
    setBurstKey((k) => k + 1);
  }, [heartBurstWired]);

  // ─── Imperative handle (R-Plan-3) ───
  useImperativeHandle(
    ref,
    () => ({
      openKebab: () => setKebabOpen(true),
      triggerLike: () => {
        barRef.current?.triggerLike();
        if (heartBurstWired) setBurstKey((k) => k + 1);
      },
      getCurrentPost: () => statefulPostRef.current,
      reset: (next: Post) => setStatefulPost(next),
      getEngagementHandle: () => barRef.current,
      getThreadHandle: () => threadRef.current,
    }),
    // heartBurstWired re-derives per render; capture via ref if needed.
    // For v0.1 simplicity, identity churns when heartBurstWired changes — acceptable.
    [heartBurstWired],
  );

  const authorId = useId();

  const handleLoadMoreLikers = useCallback(async (): Promise<PostLikeUser[]> => {
    if (!onLoadMoreLikers) return [];
    const next = await onLoadMoreLikers();
    setStatefulLikers((prev) => [...prev, ...next]);
    return next;
  }, [onLoadMoreLikers]);

  // ─── Inline panel node (only built when inline mode + a panel is open) ───
  const inlinePanelNode = useMemo(() => {
    if (!inlineModeActive || activePanel === "none") return null;
    if (activePanel === "likes") {
      return (
        <LikersStrip
          totalCount={statefulPost.likes}
          likers={statefulLikers}
          heading={labels.likersHeading}
          onLoadMore={onLoadMoreLikers ? handleLoadMoreLikers : undefined}
          moreAriaLabelTemplate={labels.likersMoreLabel}
          onClose={() => setActivePanel("none")}
          closeLabel={labels.hidePanelLabel}
        />
      );
    }
    if (activePanel === "share") {
      return (
        <ShareMenu
          users={shareSuggestions ?? []}
          onSearch={onShareSearch}
          onShareTo={(user) => {
            onShareTo?.(statefulPost.id, user);
            setActivePanel("none");
          }}
          heading={labels.shareHeading}
          searchPlaceholder={labels.shareSearchPlaceholder}
          emptyLabel={labels.shareEmptyLabel}
          onClose={() => setActivePanel("none")}
          closeLabel={labels.hidePanelLabel}
        />
      );
    }
    // comments
    return (
      <div
        style={{ maxHeight: inlineCommentsMaxHeight }}
        className="overflow-y-auto"
      >
        <CommentThread01
          ref={threadRef}
          comments={commentThread ?? []}
          currentUser={currentUser}
          pageSize={commentPageSize}
          subscribe={commentSubscribe}
          onSubscribeDelta={onSubscribeCommentDelta}
          onAddComment={onAddComment}
          onLikeComment={onLikeComment}
          onDeleteComment={onDeleteComment}
          onReportComment={onReportComment}
          onLoadMore={onLoadMoreComments}
          commentActions={commentActions}
          labels={labelsProp?.commentLabels}
        />
      </div>
    );
  }, [
    inlineModeActive,
    activePanel,
    statefulPost.id,
    statefulPost.likes,
    statefulLikers,
    labels,
    onLoadMoreLikers,
    handleLoadMoreLikers,
    shareSuggestions,
    onShareSearch,
    onShareTo,
    inlineCommentsMaxHeight,
    commentThread,
    currentUser,
    commentPageSize,
    commentSubscribe,
    onSubscribeCommentDelta,
    onAddComment,
    onLikeComment,
    onDeleteComment,
    onReportComment,
    onLoadMoreComments,
    commentActions,
    labelsProp?.commentLabels,
  ]);

  // ─── Common props bundle ───
  const baseProps = {
    post: statefulPost,
    currentUser,
    authorId,
    formattedTime,
    kebabOpen,
    onKebabOpenChange: setKebabOpen,
    kebabItems,
    engagementActions: engagementActionsArr,
    engagementBarRef: barRef,
    engagementClassName,
    engagementLabels: labelsProp?.engagementLabels,
    engagementSubscribeNoop: undefined,
    bodyMaxLines: resolvedBodyMaxLines,
    bodyClassName,
    headingAs: resolvedHeadingAs,
    labels,
    burstKey,
    heartBurstWired,
    onMediaDoubleTap: heartBurstWired ? onMediaDoubleTap : undefined,
    cardLinkable,
    linkHref,
    inlinePanelNode,
    LinkComponent,
    renderHeader,
    renderContent,
    renderMedia,
    renderEngagementBar,
    className,
    headerClassName,
    mediaClassName,
  };

  switch (variant) {
    case "feed":
      return <FeedVariant {...baseProps} />;
    case "compact":
      return <CompactVariant {...baseProps} />;
    case "list":
      return <ListVariant {...baseProps} />;
    case "detail":
      return (
        <DetailVariant
          {...baseProps}
          commentThread={commentThread ?? []}
          commentPageSize={commentPageSize}
          commentSubscribe={commentSubscribe}
          onSubscribeCommentDelta={onSubscribeCommentDelta}
          onAddComment={onAddComment}
          onLikeComment={onLikeComment}
          onDeleteComment={onDeleteComment}
          onReportComment={onReportComment}
          onLoadMoreComments={onLoadMoreComments}
          commentActions={commentActions}
          renderCommentSection={renderCommentSection}
          commentLabels={labelsProp?.commentLabels}
          threadRef={threadRef}
          commentSectionClassName={commentSectionClassName}
          commentsHeading={labels.commentsHeading}
        />
      );
  }
}

const PostCard01 = memo(PostCard01Inner);
PostCard01.displayName = "PostCard01";

export { PostCard01 };

export { PostCard01 } from "./post-card-01";
export { VerifiedBadge } from "./parts/verified-badge";
export { LikersStrip } from "./parts/likers-strip";
export { ShareMenu } from "./parts/share-menu";
export {
  defaultPostEngagementActions,
  defaultPostKebabActions,
} from "./lib/defaults";

export type {
  Post,
  PostAuthor,
  PostHandlers,
  PostCard01Props,
  PostCard01Handle,
  PostCard01Variant,
  PostCard01Labels,
  EngagementMode,
  PostLikeUser,
} from "./types";

export { DEFAULT_POST_CARD_LABELS } from "./types";

// Re-exports for consumer convenience — single import
export type { MediaItem } from "@/registry/components/media/media-carousel-01";
export type {
  Comment,
  CommentDelta,
  CommentMenuItem,
  CommentThreadCurrentUser,
  Subscribe,
  Unsubscribe,
} from "@/registry/components/data/comment-thread-01";
export type {
  EngagementAction,
  EngagementDelta,
  EngagementBar01Handle,
} from "@/registry/components/data/engagement-bar-01";

import type { ElementType, ReactNode } from "react";
import type { MediaItem } from "@/registry/components/media/media-carousel-01";
import type {
  Comment,
  CommentDelta,
  CommentMenuItem,
  CommentThreadCurrentUser,
  CommentThreadLabels,
  CommentThread01Handle,
  Subscribe,
} from "@/registry/components/data/comment-thread-01";
import type {
  EngagementAction,
  EngagementBar01Handle,
  EngagementBarLabels,
  EngagementDelta,
} from "@/registry/components/data/engagement-bar-01";

export type PostCard01Variant = "feed" | "compact" | "list" | "detail";

/**
 * Behavior of the comment + like actions:
 *  - `"inline"` (default): like splits into heart (toggle) + count (open likers panel inline);
 *    comment toggles an inline `<CommentThread01>` (with composer) below the engagement bar.
 *    Card owns the panel state. Matches the kasder PostEngagementPanel UX.
 *  - `"navigate"`: comment-icon click fires `onComment(postId)` (host navigates / scrolls);
 *    like is a single button (heart + count bundled, fires `onLike(postId, next)`). No inline panels.
 *
 * Default is `"inline"` so the canonical social UX works without opt-in. Pass `"navigate"` to
 * deactivate the inline panels for a host that wants page navigation instead.
 */
export type EngagementMode = "navigate" | "inline";

export interface PostLikeUser {
  id: string;
  name: string;
  username?: string;
  avatar?: string;
}

export interface PostAuthor {
  id: string;
  name: string;
  username?: string;
  avatar?: string;
  isVerified?: boolean;
}

export interface Post {
  id: string;
  author: PostAuthor;
  content: string;
  media?: MediaItem[];
  createdAt: Date | string | number;
  likes: number;
  isLiked?: boolean;
  comments: number;
  shares?: number;
  viewCount?: number;
  isBookmarked?: boolean;
}

/** Engagement-action handlers only — comment handlers stay separate. */
export interface PostHandlers {
  onLike?: (postId: string, nextLiked: boolean) => void;
  onComment?: (postId: string) => void;
  onShare?: (postId: string) => void;
  onBookmark?: (postId: string, nextBookmarked: boolean) => void;
}

export interface PostCard01Labels {
  verifiedBadgeLabel?: string;
  bookmark?: string;
  unbookmark?: string;
  share?: string;
  copyLink?: string;
  report?: string;
  commentsHeading?: string;
  /** Inline likers panel heading. Default "Likes". */
  likersHeading?: string;
  /** Likers panel "+N" pill aria-label template; `{count}` is replaced. Default "+{count} more". */
  likersMoreLabel?: string;
  /** Inline panel "Hide" button label. Default "Hide". */
  hidePanelLabel?: string;
  /** Share panel heading. Default "Share with…". */
  shareHeading?: string;
  /** Share panel search placeholder. Default "Search people…". */
  shareSearchPlaceholder?: string;
  /** Share panel empty-state. Default "No matches." */
  shareEmptyLabel?: string;
  formatRelativeTime?: (date: Date, now: Date) => string;
  engagementLabels?: EngagementBarLabels;
  commentLabels?: CommentThreadLabels;
}

export const DEFAULT_POST_CARD_LABELS: Required<
  Omit<
    PostCard01Labels,
    "formatRelativeTime" | "engagementLabels" | "commentLabels"
  >
> = {
  verifiedBadgeLabel: "Verified account",
  bookmark: "Bookmark",
  unbookmark: "Remove bookmark",
  share: "Share",
  copyLink: "Copy link",
  report: "Report",
  commentsHeading: "Comments",
  likersHeading: "Likes",
  likersMoreLabel: "+{count} more",
  hidePanelLabel: "Hide",
  shareHeading: "Share with…",
  shareSearchPlaceholder: "Search people…",
  shareEmptyLabel: "No matches.",
};

export interface PostCard01Props extends PostHandlers {
  variant: PostCard01Variant;
  post: Post;
  currentUser?: CommentThreadCurrentUser;

  commentThread?: Comment[];
  commentPageSize?: number;

  onAddComment?: (
    content: string,
    parentId?: string,
  ) => Promise<Comment | void> | Comment | void;
  onLikeComment?: (commentId: string, nextLiked: boolean) => void;
  onDeleteComment?: (commentId: string) => void;
  onReportComment?: (commentId: string) => void;
  onLoadMoreComments?: (page: number) => Promise<Comment[]>;
  onCopyLink?: (postId: string) => void;
  onReport?: (postId: string) => void;

  engagementSubscribe?: Subscribe<EngagementDelta>;
  commentSubscribe?: Subscribe<CommentDelta>;
  onSubscribeEngagementDelta?: (delta: EngagementDelta) => void;
  onSubscribeCommentDelta?: (delta: CommentDelta) => void;

  /** Card overlay-link target + Copy-link kebab item. Ignored for overlay-link in detail variant. */
  getHref?: (post: Post) => string;
  /** Polymorphic root component for overlay-link. Default "a". */
  linkComponent?: ElementType;
  /** Opt-out for the canonical heart-burst flow. Default false. */
  disableHeartBurst?: boolean;

  // ─── Inline engagement panels (kasder UX) ───
  /**
   * `"navigate"` (default): comment click → `onComment(postId)`; no inline panels.
   * `"inline"`: comment click toggles `<CommentThread01>` panel; like opens inline likers strip.
   */
  engagementMode?: EngagementMode;
  /** Pre-loaded likers (for inline likers panel). Only used when `engagementMode === "inline"`. */
  likers?: PostLikeUser[];
  /** Fetch more likers — host returns appended page; component appends to local state. */
  onLoadMoreLikers?: () => Promise<PostLikeUser[]>;

  /** Recent / suggested users for the share panel. When provided, share button opens
   * an inline searchable user list (kasder UX). Otherwise share fires `onShare(postId)`. */
  shareSuggestions?: PostLikeUser[];
  /** Optional async search for the share panel. Receives the query, returns matching users. */
  onShareSearch?: (query: string) => Promise<PostLikeUser[]>;
  /** Fired when the user picks a recipient from the share panel. */
  onShareTo?: (postId: string, recipient: PostLikeUser) => void;
  /** Max-height of the inline comments panel before scroll. Default `"24rem"` (~384px). */
  inlineCommentsMaxHeight?: string;
  /** Open one of the inline panels by default on mount (only when `engagementMode === "inline"`). */
  defaultInlinePanel?: "none" | "likes" | "comments";
  /** Auto-open the likers panel on like (matches kasder). Default true under inline mode. */
  openLikersOnLike?: boolean;

  renderHeader?: (
    post: Post,
    helpers: { currentUser?: CommentThreadCurrentUser },
  ) => ReactNode;
  renderContent?: (post: Post) => ReactNode;
  renderMedia?: (
    media: MediaItem[],
    helpers: { onDoubleTap?: () => void },
  ) => ReactNode;
  engagementActions?: (
    post: Post,
    handlers: PostHandlers,
    variant: PostCard01Variant,
  ) => EngagementAction[];
  renderEngagementBar?: (
    post: Post,
    defaults: { actions: EngagementAction[] },
  ) => ReactNode;
  kebabActions?: (post: Post) => CommentMenuItem[];
  commentActions?: (
    comment: Comment,
    helpers: {
      currentUser?: CommentThreadCurrentUser;
      isOwn: boolean;
      depth: number;
    },
  ) => CommentMenuItem[];
  renderCommentSection?: (
    post: Post,
    handlers: {
      onAddComment?: PostCard01Props["onAddComment"];
      onLikeComment?: PostCard01Props["onLikeComment"];
      onDeleteComment?: PostCard01Props["onDeleteComment"];
      onReportComment?: PostCard01Props["onReportComment"];
      onLoadMoreComments?: PostCard01Props["onLoadMoreComments"];
    },
  ) => ReactNode;

  headingAs?: "h2" | "h3" | "h4";
  bodyMaxLines?: number;

  labels?: PostCard01Labels;
  className?: string;
  headerClassName?: string;
  bodyClassName?: string;
  mediaClassName?: string;
  engagementClassName?: string;
  commentSectionClassName?: string;

  ref?: React.Ref<PostCard01Handle>;
}

export interface PostCard01Handle {
  openKebab: () => void;
  /** Card-level "canonical Instagram tap" — flips like via bar AND bumps burst counter (when wired). */
  triggerLike: () => void;
  /** Read the current local mirror state (post + engagement deltas applied). */
  getCurrentPost: () => Post;
  /** Replace the post (re-derives local engagement mirror on next render). */
  reset: (next: Post) => void;
  getEngagementHandle: () => EngagementBar01Handle | null;
  getThreadHandle: () => CommentThread01Handle | null;
}

"use client";

import { memo } from "react";
import { cn } from "@/lib/utils";
import { ExpandableText01 } from "@/registry/components/data/expandable-text-01";
import { MediaCarousel01 } from "@/registry/components/media/media-carousel-01";
import {
  EngagementBar01,
  EngagementHeartBurst,
} from "@/registry/components/data/engagement-bar-01";
import { PostHeader } from "./post-header";
import type { VariantInnerProps } from "./variant-shared";

function FeedVariantInner(props: VariantInnerProps) {
  const {
    post,
    currentUser,
    authorId,
    formattedTime,
    kebabOpen,
    onKebabOpenChange,
    kebabItems,
    engagementActions,
    engagementBarRef,
    engagementClassName,
    engagementLabels,
    engagementSubscribeNoop,
    bodyMaxLines,
    bodyClassName,
    headingAs,
    labels,
    burstKey,
    heartBurstWired,
    onMediaDoubleTap,
    cardLinkable,
    linkHref,
